import React from "react";
import "./Map.css";

// District colors based on your image
const districtColors = {
  "Konkan": "#6c757d",      // grey
  "Pune": "#28a745",        // green
  "Nashik": "#fadb14",      // yellow
  "Nagpur": "#f0ad4e",      // orange
  "Amravati": "#f38fa9",    // pink
  "Chhatrapati Sambhajinagar": "#6f42c1", // purple
  "Mumbai": "#343a40"       // dark grey
};

const districts = [
  "Mumbai", "Thane", "Palghar", "Raigad", "Ratnagiri", "Sindhudurg", // Konkan
  "Pune", "Solapur", "Satara", "Sangli", "Kolhapur",                 // Pune division
  "Nashik", "Ahmednagar", "Jalgaon", "Dhule",                        // Nashik division
  "Nagpur", "Wardha", "Bhandara", "Gondia", "Chandrapur", "Gadchiroli", // Nagpur
  "Akola", "Amravati", "Yavatmal", "Washim", "Buldhana"             // Amravati
];

const Map = ({ onDistrictClick }) => {
  return (
    <div className="maharashtra-map">
      {districts.map(d => (
        <div
          key={d}
          className="district"
          style={{ backgroundColor: districtColors[getDivision(d)] || "#dee2e6" }}
          onClick={() => onDistrictClick(d)}
          title={d}
        >
          {d}
        </div>
      ))}
    </div>
  );
};

// Helper to get division color
function getDivision(district) {
  const konkan = ["Mumbai", "Thane", "Palghar", "Raigad", "Ratnagiri", "Sindhudurg"];
  const pune = ["Pune", "Solapur", "Satara", "Sangli", "Kolhapur"];
  const nashik = ["Nashik", "Ahmednagar", "Jalgaon", "Dhule"];
  const nagpur = ["Nagpur", "Wardha", "Bhandara", "Gondia", "Chandrapur", "Gadchiroli"];
  const amravati = ["Akola", "Amravati", "Yavatmal", "Washim", "Buldhana"];
  if (konkan.includes(district)) return "Konkan";
  if (pune.includes(district)) return "Pune";
  if (nashik.includes(district)) return "Nashik";
  if (nagpur.includes(district)) return "Nagpur";
  if (amravati.includes(district)) return "Amravati";
  return null;
}

export default Map;
